namespace sv_b802310d5c5442c4a29e25934da0d868.Services;

public record Product(int Id, string Name, decimal Price, string Category, double Rating, bool InStock, string ImageUrl);
public record ProductFilter(List<string>? Categories, decimal? MinPrice, decimal? MaxPrice, bool InStockOnly);
public record PagedResult<T>(List<T> Items, int TotalCount, int Page, int PageSize);

public interface IProductService
{
    Task<PagedResult<Product>> SearchAsync(ProductFilter filter, string sortBy, int page, int pageSize);
    Task<List<string>> GetCategoriesAsync();
}

@page "/catalog"
@using sv_b802310d5c5442c4a29e25934da0d868.Services
@inject IProductService ProductService
@rendermode InteractiveServer

<PageTitle>Product Catalog</PageTitle>

<h1>Product Catalog</h1>

@if (_error is not null)
{
    <div class="alert alert-danger" role="alert">
        <strong>Error:</strong> @_error
        <button class="btn btn-sm btn-outline-danger ms-3" @onclick="RetryAsync">Retry</button>
    </div>
}
else
{
    <div class="catalog-layout">
        <!-- Left Sidebar -->
        <aside class="catalog-sidebar">
            <h5>Filters</h5>

            <div class="filter-section">
                <label class="fw-bold mb-1">Category</label>
                @if (_categories is null)
                {
                    <p class="text-muted"><em>Loading…</em></p>
                }
                else
                {
                    @foreach (var category in _categories)
                    {
                        <div class="form-check">
                            <input class="form-check-input" type="checkbox" id="@($"cat-{category}")"
                                   checked="@(_selectedCategories.Contains(category))"
                                   @onchange="e => ToggleCategory(category, (bool)e.Value!)" />
                            <label class="form-check-label" for="@($"cat-{category}")">@category</label>
                        </div>
                    }
                }
            </div>

            <div class="filter-section">
                <label class="fw-bold mb-1">Price Range</label>
                <div class="d-flex gap-2 align-items-center">
                    <input type="number" class="form-control form-control-sm" placeholder="Min"
                           @bind="_minPrice" @bind:event="onchange" min="0" step="0.01" />
                    <span>–</span>
                    <input type="number" class="form-control form-control-sm" placeholder="Max"
                           @bind="_maxPrice" @bind:event="onchange" min="0" step="0.01" />
                </div>
            </div>

            <div class="filter-section">
                <div class="form-check">
                    <input class="form-check-input" type="checkbox" id="inStockOnly"
                           @bind="_inStockOnly" />
                    <label class="form-check-label" for="inStockOnly">In Stock Only</label>
                </div>
            </div>

            <div class="d-flex flex-column gap-2 mt-3">
                <button class="btn btn-primary" @onclick="ApplyFiltersAsync">Apply Filters</button>
                <button class="btn btn-outline-secondary" @onclick="ClearFiltersAsync">Clear Filters</button>
            </div>
        </aside>

        <!-- Main Content -->
        <main class="catalog-main">
            <!-- Toolbar -->
            <div class="catalog-toolbar">
                <div class="d-flex align-items-center gap-3">
                    <label class="fw-bold mb-0" for="sortSelect">Sort by:</label>
                    <select id="sortSelect" class="form-select form-select-sm w-auto"
                            @bind="_sortBy" @bind:after="OnSortChangedAsync">
                        <option value="price_asc">Price: Low to High</option>
                        <option value="price_desc">Price: High to Low</option>
                        <option value="name_asc">Name: A–Z</option>
                        <option value="rating_desc">Rating: Highest</option>
                    </select>
                </div>

                @if (_result is not null)
                {
                    var first = (_result.Page - 1) * _result.PageSize + 1;
                    var last = Math.Min(_result.Page * _result.PageSize, _result.TotalCount);
                    <span class="text-muted">Showing @first–@last of @_result.TotalCount products</span>
                }
            </div>

            <!-- Product Grid -->
            @if (_loading)
            {
                <div class="d-flex justify-content-center py-5">
                    <div class="spinner-border text-primary" role="status">
                        <span class="visually-hidden">Loading…</span>
                    </div>
                </div>
            }
            else if (_result is null || _result.Items.Count == 0)
            {
                <div class="alert alert-info text-center my-4" role="alert">
                    No products found. Try adjusting your filters.
                </div>
            }
            else
            {
                <div class="product-grid">
                    @foreach (var product in _result.Items)
                    {
                        <div class="card product-card" @onclick="() => OnProductSelected(product)"
                             role="button" tabindex="0">
                            <div class="product-image-placeholder" title="@product.Name">
                                @product.Name
                            </div>
                            <div class="card-body">
                                <h6 class="card-title">@product.Name</h6>
                                <p class="card-text fw-bold text-primary mb-1">@product.Price.ToString("C")</p>
                                <p class="card-text mb-1">@GetStarRating(product.Rating)</p>
                                @if (!product.InStock)
                                {
                                    <span class="badge bg-danger mb-2">Out of Stock</span>
                                }
                                <button class="btn btn-sm btn-success w-100"
                                        disabled="@(!product.InStock)"
                                        @onclick="() => { }" @onclick:stopPropagation="true">
                                    Add to Cart
                                </button>
                            </div>
                        </div>
                    }
                </div>

                <!-- Pagination -->
                @if (_totalPages > 1)
                {
                    <nav aria-label="Product pagination" class="mt-4">
                        <ul class="pagination justify-content-center">
                            <li class="page-item @(_currentPage == 1 ? "disabled" : "")">
                                <button class="page-link" disabled="@(_currentPage == 1)"
                                        @onclick="() => GoToPageAsync(_currentPage - 1)">Previous</button>
                            </li>
                            @for (var i = 1; i <= _totalPages; i++)
                            {
                                var pageNum = i;
                                <li class="page-item @(pageNum == _currentPage ? "active" : "")">
                                    <button class="page-link" @onclick="() => GoToPageAsync(pageNum)">@pageNum</button>
                                </li>
                            }
                            <li class="page-item @(_currentPage == _totalPages ? "disabled" : "")">
                                <button class="page-link" disabled="@(_currentPage == _totalPages)"
                                        @onclick="() => GoToPageAsync(_currentPage + 1)">Next</button>
                            </li>
                        </ul>
                    </nav>
                }
            }
        </main>
    </div>
}

@code {
    [Parameter] public EventCallback<Product> OnProductClicked { get; set; }

    private List<string>? _categories;
    private HashSet<string> _selectedCategories = new();
    private decimal? _minPrice;
    private decimal? _maxPrice;
    private bool _inStockOnly;
    private string _sortBy = "price_asc";

    private PagedResult<Product>? _result;
    private int _currentPage = 1;
    private int _totalPages;
    private const int PageSize = 12;
    private bool _loading;
    private string? _error;

    protected override async Task OnInitializedAsync()
    {
        try
        {
            _loading = true;
            var categoriesTask = ProductService.GetCategoriesAsync();
            var searchTask = SearchProductsAsync();
            _categories = await categoriesTask;
            await searchTask;
        }
        catch (Exception ex)
        {
            _error = ex.Message;
        }
        finally
        {
            _loading = false;
        }
    }

    private async Task SearchProductsAsync()
    {
        _loading = true;
        _error = null;

        try
        {
            var filter = new ProductFilter(
                _selectedCategories.Count > 0 ? _selectedCategories.ToList() : null,
                _minPrice,
                _maxPrice,
                _inStockOnly
            );

            _result = await ProductService.SearchAsync(filter, _sortBy, _currentPage, PageSize);
            _totalPages = (int)Math.Ceiling((double)_result.TotalCount / PageSize);
        }
        catch (Exception ex)
        {
            _error = ex.Message;
        }
        finally
        {
            _loading = false;
        }
    }

    private void ToggleCategory(string category, bool isChecked)
    {
        if (isChecked)
            _selectedCategories.Add(category);
        else
            _selectedCategories.Remove(category);
    }

    private async Task ApplyFiltersAsync()
    {
        _currentPage = 1;
        await SearchProductsAsync();
    }

    private async Task ClearFiltersAsync()
    {
        _selectedCategories.Clear();
        _minPrice = null;
        _maxPrice = null;
        _inStockOnly = false;
        _currentPage = 1;
        await SearchProductsAsync();
    }

    private async Task OnSortChangedAsync()
    {
        _currentPage = 1;
        await SearchProductsAsync();
    }

    private async Task GoToPageAsync(int page)
    {
        if (page < 1 || page > _totalPages) return;
        _currentPage = page;
        await SearchProductsAsync();
    }

    private void OnProductSelected(Product product)
    {
        if (OnProductClicked.HasDelegate)
            OnProductClicked.InvokeAsync(product);
    }

    private async Task RetryAsync()
    {
        _error = null;
        await OnInitializedAsync();
    }

    private static string GetStarRating(double rating)
    {
        var rounded = (int)Math.Round(rating);
        return new string('★', rounded) + new string('☆', 5 - rounded);
    }
}

.catalog-layout {
    display: flex;
    gap: 1.5rem;
}

.catalog-sidebar {
    flex: 0 0 25%;
    max-width: 25%;
    padding: 1rem;
    border-right: 1px solid #dee2e6;
}

.catalog-main {
    flex: 1;
    min-width: 0;
}

.filter-section {
    margin-bottom: 1rem;
}

.catalog-toolbar {
    display: flex;
    justify-content: space-between;
    align-items: center;
    flex-wrap: wrap;
    gap: 0.5rem;
    margin-bottom: 1rem;
    padding: 0.75rem;
    background-color: #f8f9fa;
    border-radius: 0.375rem;
}

.product-grid {
    display: grid;
    grid-template-columns: repeat(auto-fill, minmax(220px, 1fr));
    gap: 1rem;
}

.product-card {
    cursor: pointer;
    transition: box-shadow 0.15s ease-in-out, transform 0.15s ease-in-out;
}

.product-card:hover {
    box-shadow: 0 0.25rem 0.75rem rgba(0, 0, 0, 0.15);
    transform: translateY(-2px);
}

.product-image-placeholder {
    height: 160px;
    background-color: #e9ecef;
    display: flex;
    align-items: center;
    justify-content: center;
    color: #6c757d;
    font-size: 0.875rem;
    text-align: center;
    padding: 1rem;
    border-bottom: 1px solid #dee2e6;
}

